import org.springframework.data.jpa.repository.*;
import jakarta.persistence.QueryHint;
import java.time.LocalDateTime;
import java.util.List;
import static org.hibernate.jpa.HibernateHints.*;
import static org.hibernate.jpa.SpecHints.*;

public interface PaymentRepository extends JpaRepository<Payment, Long> {

    // HINT_READONLY: Hibernate skips dirty checking (no snapshot comparison after each read)
    // Performance gain: ~10-30% on large result sets
    @QueryHints({
        @QueryHint(name = HINT_READONLY, value = "true")
    })
    List<Payment> findByMerchantIdAndStatusAndCreatedAtAfter(
        String merchantId, String status, LocalDateTime since);

    // JOIN FETCH: avoid N+1 (load merchant in same query)
    // HINT_FETCH_SIZE: how many rows to fetch from DB at once (streaming)
    @Query("""
        SELECT p FROM Payment p
        JOIN FETCH p.merchant m
        WHERE p.merchantId = :merchantId
        AND p.createdAt > :since
        ORDER BY p.createdAt DESC
    """)
    @QueryHints({
        @QueryHint(name = HINT_READONLY,   value = "true"),
        @QueryHint(name = HINT_FETCH_SIZE, value = "100")  // fetch 100 rows at a time from cursor
    })
    List<Payment> findWithMerchantSince(String merchantId, LocalDateTime since);

    // HINT_READONLY: skip dirty check (Hibernate won't track changes to returned entities)
    // HINT_FETCH_SIZE: streams rows from DB 100 at a time (avoids loading all 10K rows at once)
    // JOIN FETCH: loads merchant in ONE query instead of N+1 separate queries
}

