import org.springframework.data.domain.*;
import org.springframework.data.jpa.repository.*;
import org.springframework.data.repository.query.Param;
import java.util.List;

public interface PaymentPaginationRepository extends JpaRepository<Payment, Long> {

    // OFFSET pagination (BAD for large offsets):
    // SELECT * FROM payments ORDER BY id OFFSET 10000 LIMIT 20;
    // PostgreSQL: scans and discards 10,000 rows before returning 20
    // OFFSET 500,000: scans and discards 500K rows = 2-3 seconds!
    Page<Payment> findByMerchantId(String merchantId, Pageable pageable);

    // KEYSET pagination (GOOD — O(1) regardless of position):
    // SELECT * FROM payments WHERE id > :lastId ORDER BY id LIMIT 20;
    // Uses index on id — jumps directly to position, no scan!
    @Query("""
        SELECT p FROM Payment p
        WHERE p.merchantId = :merchantId
        AND p.id > :lastId
        ORDER BY p.id ASC
    """)
    List<Payment> findNextPage(
        @Param("merchantId") String merchantId,
        @Param("lastId") Long lastId,
        Pageable pageable);

    // OFFSET acceptable when:
    // - Total rows < 10,000 (scan is fast)
    // - Admin-only (performance not critical)
    // - Random page access needed (keyset only allows sequential navigation)
    //
    // KEYSET required when:
    // - User-facing, high-traffic list
    // - Table has > 100K rows
    // - Infinite scroll / cursor-based API
}

