import java.time.LocalDateTime;
import java.util.List;

@DataJpaTest
class PaymentQueryTest {
    @Autowired PaymentRepository repo;
    @Autowired EntityManagerFactory emf;

    Statistics stats;

    @BeforeEach void setup() {
        stats = emf.unwrap(org.hibernate.SessionFactory.class).getStatistics();
        stats.setStatisticsEnabled(true);
        stats.clear();

        // Insert test data:
        var merchant = new Merchant("MRC-001", "Razorpay Test");
        // repo.save(merchant) etc. — abbreviated for space
    }

    @Test void findPayments_noNPlusOne() {
        // When: query with JOIN FETCH
        LocalDateTime since = LocalDateTime.now().minusDays(7);
        List<Payment> payments = repo.findWithMerchantSince("MRC-001", since);

        // Then: exactly 1 SQL query (JOIN FETCH, not N+1)
        long queryCount = stats.getQueryExecutionCount();
        assertEquals(1, queryCount,
            "Expected 1 query (JOIN FETCH), but got: " + queryCount);
    }

    @Test void readOnlyHint_doesNotDirtyCheck() {
        // HINT_READONLY prevents dirty check — entity modifications not persisted:
        List<Payment> payments = repo.findByMerchantIdAndStatusAndCreatedAtAfter(
            "MRC-001", "PENDING", LocalDateTime.now().minusDays(1));
        // Even if we modify: emf won't flush changes (read-only)
        assertNotNull(payments);
    }
}

import org.springframework.stereotype.*;
import org.springframework.transaction.annotation.Transactional;
import java.util.*;
import java.util.stream.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// application.yml for batch inserts:
// spring.jpa.properties:
//   hibernate.jdbc.batch_size: 50          # insert 50 rows per JDBC batch
//   hibernate.order_inserts: true          # reorder to maximize batch efficiency
//   hibernate.order_updates: true          # same for updates
//   hibernate.generate_statistics: true    # (dev only) confirm batching works

@Service
class PaymentBatchService {
    private final PaymentRepository repo;
    PaymentBatchService(PaymentRepository r) { repo = r; }

    // NAIVE (slow): 10,000 individual INSERT statements:
    // payments.forEach(p -> repo.save(p));  ← 10,000 round trips!

    // OPTIMIZED: JPA saveAll with batch_size=50
    // → 200 batch INSERT statements (10,000/50) instead of 10,000 individual ones
    @Transactional
    public void saveBatch(List<Payment> payments) {
        repo.saveAll(payments);  // Hibernate batches internally (batch_size=50)
    }

    // JDBC Template for maximum performance (bypasses Hibernate overhead):
    // jdbcTemplate.batchUpdate(
    //   "INSERT INTO payments(id, amount, merchant_id, status, created_at) VALUES (?,?,?,?,?)",
    //   new BatchPreparedStatementSetter() { ... }
    // );
}

@SpringBootTest
class BatchInsertTest {
    @Autowired PaymentBatchService svc;

    @Test void batch_completesQuickly() {
        List<Payment> payments = IntStream.range(0, 100)
            .mapToObj(i -> new Payment("MRC-" + i, 999.0))
            .collect(java.util.stream.Collectors.toList());

        long start = System.currentTimeMillis();
        svc.saveBatch(payments);
        long elapsed = System.currentTimeMillis() - start;

        System.out.println("Batch insert 100 records: " + elapsed + "ms");
        // In-memory H2: should complete in < 500ms
        assertTrue(elapsed < 2000, "Batch insert should complete in < 2s");
    }
}

