import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// application.yml slow query logging:
// spring.jpa.properties:
//   hibernate.session.events.log.LOG_QUERIES_SLOWER_THAN_MS: 100
//   # Logs any JPA query taking > 100ms to SLF4J (at WARN level)

// Custom Micrometer integration for query timing:
@Service
class QueryMetricsService {
    private final MeterRegistry reg;
    private final Timer queryTimer;
    private final Counter slowQueryCounter;

    QueryMetricsService(MeterRegistry r) {
        reg = r;
        queryTimer = Timer.builder("db.query.duration")
            .publishPercentiles(0.5, 0.95, 0.99)
            .register(reg);
        slowQueryCounter = Counter.builder("db.query.slow")
            .description("Queries taking > 100ms")
            .register(reg);
    }

    public <T> T time(java.util.function.Supplier<T> query) {
        return queryTimer.record(() -> {
            long start = System.currentTimeMillis();
            T result = query.get();
            long elapsed = System.currentTimeMillis() - start;
            if (elapsed > 100) slowQueryCounter.increment();
            return result;
        });
    }
}

// Prometheus alert:
// - alert: SlowQueryRate
//   expr: rate(db_query_slow_total[5m]) > 0.1
//   annotations: { summary: 'More than 0.1 slow queries/sec for 5min' }

@SpringBootTest
class QueryMetricsTest {
    @Autowired QueryMetricsService svc;
    @Autowired MeterRegistry reg;

    @Test void timer_registered() {
        assertNotNull(reg.find("db.query.duration").timer());
    }
    @Test void timing_works() {
        svc.time(() -> "result");
        assertTrue(reg.find("db.query.duration").timer().count() >= 1);
    }
}

