import org.springframework.jdbc.datasource.lookup.AbstractRoutingDataSource;
import org.springframework.context.annotation.*;
import javax.sql.DataSource;
import java.util.*;
import org.springframework.transaction.support.TransactionSynchronizationManager;

enum DbRole { PRIMARY, REPLICA }

class RoutingDataSource extends AbstractRoutingDataSource {
    @Override
    protected Object determineCurrentLookupKey() {
        // @Transactional(readOnly=true) → route to replica
        return TransactionSynchronizationManager.isCurrentTransactionReadOnly()
            ? DbRole.REPLICA : DbRole.PRIMARY;
    }
}

@Configuration
public class DataSourceRoutingConfig {
    @Bean
    @Primary
    public DataSource routingDataSource(
            @Qualifier("primaryDs") DataSource primary,
            @Qualifier("replicaDs") DataSource replica) {
        var routing = new RoutingDataSource();
        routing.setTargetDataSources(Map.of(
            DbRole.PRIMARY, primary,
            DbRole.REPLICA, replica
        ));
        routing.setDefaultTargetDataSource(primary);
        return routing;
    }
}

// USAGE:
// @Transactional(readOnly=true)  → replica
// public List<Payment> findAll() { return repo.findAll(); }
//
// @Transactional                  → primary
// public Payment save(Payment p) { return repo.save(p); }

// SCALE BENEFIT:
// Without replica: all 1000 req/s hit primary DB
// With replica (3 replicas): reads (80%) → 3 replicas (267 req/s each)
//                            writes (20%) → primary (200 req/s)
// Primary CPU: 80% less than before → room for write-heavy operations

public class ReadReplicaDemo { public static void main(String[] a) {
    System.out.println("@Transactional(readOnly=true) → replica, reads → primary");
} }

